SELECT
  reservas_credito_an.iata,
  reservas_credito_an.rec_loc,
  reservas_credito_an.booking_date,
  reservas_credito_an.nbr_of_pax,
  sum(reservas_credito_an.an_payment) as [An Payment]
FROM
  (
  select p.iata, p.rec_loc, p.booking_date, p.nbr_of_pax, an.payment_amount as an_payment
from factPnr p
join (select rec_loc, sum(payment_amount) as payment_amount
from vueling_ods.dbo.PNR_PAYMENT
where type_code='AN'
and payment_amount>0
group by rec_loc
) py on py.rec_loc=p.rec_loc
join (select rec_loc, sum(payment_amount) as payment_amount
from vueling_ods.dbo.PNR_PAYMENT
where type_code='AN'
group by rec_loc
) an on an.rec_loc=p.rec_loc
and p.booking_date>='{0}'
  )  reservas_credito_an
WHERE

   reservas_credito_an.iata  IN ('57246744', '78209073', '78213796', '78240971', '78260836', '78260851', '78261492', '78261632', '78266274', '78280672', '78294510', '49966860', '20245831', 'NL85329914', '8334546', '72324781', '867780566', '91222784', '78237084', '78297494', '20265162', '78203160', '57210156', 'ZPYVWAHYG7', 'CHE1789779', '20256504', 'Q7UMHJPVZN', '20262174', '78268934', 'B38900254', '78282013', '78243922', '8924481008', '590702048', '3827457', '78276166', '78210425', 'B64870579', 'B55039424', '46739194C', 'B65749194', 'B64554637', '78297962', '78298964', '78251246', '78224624', '78218490', '78245613', 'B55043988', '78214813', '78294425', '78244342', '78259720', '78280576', '78265143', '78217543', 'B17841362', '46940601Q', '78226326', '78243325', '78257362', 'B65984585', '78274136', '78208104', 'B65203390', '78276855', '78231860', '78205901', '78268680', '78230025', '78252053', '78256150', '78277404', '78208675', 'B53423307', '78298894', '78267420', '32044897D', '78292443', 'B46178364', '78272246', 'B-25799180', '78209176', '78212481', '78213763', '78213800', '78217834', '78217845', '78232593', '78234520', '78239593', '78244250', '78250255', '78250270', '78253906', '78253976', '78253980', '78255391', '78255413', '78255424', '78256776', '78256780', '78257620', '78257631', '78257664', '78259300', '78260394', '78260405', '78260711', '78260722', '78260744', '78260766', '78260770', '78260781', '78260803', '78260814', '78260825', '78260840', '78260862', '78260873', '78260910', '78260921', '78260932', '78260943', '78260954', '78260965', '78261433', '78261444', '78261455', '78261466', '78261470', '78261525', '78264502', '78265854', '78265994', '78266112', '78266381', '78266392', '78271012', '78271023', '78271104', '78271244', '78274011', '78274792', '78274803', '78274836', '78274840', '78274851', '78277931', '78277975', '78277986', '78278001', '78278491', '78278686', '78278690', '78278734', '78278771', '78278970', '78279036', '78279040', '78279051', '78279062